/**
 * A radio-group of available color themes with preview swatches.
 * Must be rendered inside a `ThemeProvider`.
 */
export function ThemeSelector() {
  const { theme: activeTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
