import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import { DEFAULT_THEME_ID, type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:color-theme";

export interface ThemeContextValue {
  readonly theme: Theme;
  readonly setTheme: (id: string) => void;
  readonly availableThemes: ReadonlyArray<Theme>;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

function getStoredThemeId(): string {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored !== null && getTheme(stored) !== undefined) return stored;
  return DEFAULT_THEME_ID;
}

function resolveTheme(id: string): Theme {
  const found = getTheme(id);
  if (found !== undefined) return found;
  // Fallback to default — safe because DEFAULT_THEME_ID is always in BUILT_IN_THEMES
  const def = getTheme(DEFAULT_THEME_ID);
  // oxlint-disable-next-line @typescript-eslint/no-non-null-assertion
  return def!;
}

function applyColorTheme(theme: Theme): void {
  const root = document.documentElement;

  // Suppress transitions during the swap
  root.classList.add("no-transitions");

  // Core semantic CSS custom properties — these override the stylesheet values
  // since inline styles always take precedence on the same element.
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--card", theme.colors.sidebar);
  root.style.setProperty("--card-foreground", theme.colors.foreground);
  root.style.setProperty("--popover", theme.colors.sidebar);
  root.style.setProperty("--popover-foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);

  // Theme-specific extension vars (for editor/terminal/statusbar surfaces)
  root.style.setProperty("--t3-editor-bg", theme.colors.editor);
  root.style.setProperty("--t3-terminal-bg", theme.colors.terminal);
  root.style.setProperty("--t3-statusbar-bg", theme.colors.statusBar);

  // Typography
  document.body.style.fontFamily = theme.fontFamily;
  document.body.style.fontSize = theme.fontSize;

  // Force a reflow so the no-transitions class takes effect before removal
  // oxlint-disable-next-line no-unused-expressions
  root.offsetHeight;
  requestAnimationFrame(() => {
    root.classList.remove("no-transitions");
  });
}

// Apply immediately on module load to prevent a flash of unstyled theme
applyColorTheme(resolveTheme(getStoredThemeId()));

export function ThemeProvider({ children }: { readonly children: ReactNode }) {
  const [themeId, setThemeId] = useState<string>(getStoredThemeId);
  const availableThemes = useMemo(() => listThemes(), []);
  const theme = useMemo(() => resolveTheme(themeId), [themeId]);

  const setTheme = useCallback((id: string) => {
    const resolved = getTheme(id);
    if (resolved === undefined) return;
    localStorage.setItem(STORAGE_KEY, id);
    setThemeId(id);
    applyColorTheme(resolved);
  }, []);

  // Keep the DOM in sync whenever the theme changes (e.g. after SSR hydration or
  // if the stored value was updated from another tab in the future).
  useEffect(() => {
    applyColorTheme(theme);
  }, [theme]);

  const value = useMemo<ThemeContextValue>(
    () => ({ theme, setTheme, availableThemes }),
    [theme, setTheme, availableThemes],
  );

  return <ThemeContext value={value}>{children}</ThemeContext>;
}

/**
 * Returns the current color theme, a setter, and the list of available themes.
 * Must be called inside a `ThemeProvider`.
 */
export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (ctx === null) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return ctx;
}

